function normalizeBaseUrl(raw: string, fallbackPort: string) {
  try {
    const url = new URL(raw || `${window.location.protocol}//${window.location.hostname}:${fallbackPort}`);
    if (['0.0.0.0', '127.0.0.1', 'localhost'].includes(url.hostname) && window.location.hostname && window.location.hostname !== '0.0.0.0') url.hostname = window.location.hostname;
    return url.toString().replace(/\/$/, '');
  } catch { return raw; }
}
