function readStored<T>(key: string, fallback: T): T {
  try { const raw = localStorage.getItem(key); return raw ? { ...fallback as any, ...JSON.parse(raw) } : fallback; } catch { return fallback; }
}
function writeStored(key: string, value: unknown) {
  try { localStorage.setItem(key, JSON.stringify(value)); } catch {}
}
function rangeFromStored(value: any) {
  return Array.isArray(value) && value[0] && value[1] ? [dayjs(value[0]), dayjs(value[1])] : null;
}
function rangeToStored(value: any) {
  return Array.isArray(value) && value[0] && value[1] ? [value[0].toISOString(), value[1].toISOString()] : null;
}

