  const openSample=async()=>{if(!requireUiFeature("auto_field_detect"))return;setSampleMode('history');setSampleListCandidates([]);if(!ruleForm.url_pattern.trim())return message.warning('请先填写 URL 匹配');setSampleOpen(true);setSampleLoading(true);try{const {data}=await api.get('/api/rules/sample-fields',{params:{urlPattern:ruleForm.url_pattern.trim(),responseListPath:ruleForm.response_list_path||undefined,method:ruleForm.method||undefined}});const fields=data.data?.fields||[];setSampleFields(fields);setSampleInfo(data.data||{});const preferred=new Set(['nick','shopInfo.title','item_id','realSales','price','priceShow.price','title','auctionURL','pic_path']);setSampleSelectedKeys(fields.filter((f:SampleField)=>preferred.has(f.path)).map((f:SampleField)=>f.path));if(!fields.length)message.warning('没有找到样本字段，请先捕获并上报该接口');}catch(e:any){handleApiError(e);}finally{setSampleLoading(false);}};
